function normalizePlace(v){return(v||'').replace(/\s*\(.+\)\s*$/,'').trim().toLowerCase();}
function attachDatalists(){
  if(!document.getElementById('location-options')){
    const dl=document.createElement('datalist');dl.id='location-options';
    locationOptions.forEach(v=>{const opt=document.createElement('option');opt.value=v;dl.appendChild(opt);});
    document.body.appendChild(dl);
  }
  document.querySelectorAll('[data-location-input]').forEach(el=>{
    el.addEventListener('input',()=>{
      const value=(el.value||'').trim();
      if(value.length>=2) el.setAttribute('list','location-options');
      else el.removeAttribute('list');
    });
    if(((el.value||'').trim().length)>=2) el.setAttribute('list','location-options');
    else el.removeAttribute('list');
  });
}
function setDateBounds(){const today=new Date();const max=new Date(today.getTime()+364*24*60*60*1000);const fmt=d=>d.toISOString().slice(0,10);document.querySelectorAll('input[type="date"]').forEach(inp=>{inp.min=fmt(today);inp.max=fmt(max);});}
function setTripType(type,host){host.querySelectorAll('.trip-tab').forEach(btn=>btn.classList.toggle('active',btn.dataset.trip===type));const multi=host.querySelector('.multi-city-shell');const round=host.querySelectorAll('.roundtrip-only');if(multi)multi.style.display=type==='multicity'?'block':'none';round.forEach(el=>el.style.display=type==='roundtrip'?'':'none');host.dataset.tripType=type;}
function addMultiCityRow(shell,data={}){const wrap=shell.querySelector('.multi-city-rows');if(!wrap)return;const row=document.createElement('div');row.className='multi-row';row.innerHTML=`<input data-location-input placeholder="Origin" value="${data.origin||''}"><input data-location-input placeholder="Destination" value="${data.destination||''}"><input type="date" value="${data.departDate||''}"><button type="button" class="icon-remove" aria-label="Remove leg">−</button>`;wrap.appendChild(row);row.querySelector('.icon-remove').addEventListener('click',()=>row.remove());attachDatalists();setDateBounds();}
function bindTripTypeControls(){document.querySelectorAll('[data-trip-switcher]').forEach(host=>{const start=host.dataset.defaultTrip||'roundtrip';setTripType(start,host);host.querySelectorAll('.trip-tab').forEach(btn=>btn.addEventListener('click',()=>setTripType(btn.dataset.trip,host)));const addBtn=host.querySelector('[data-add-multi-city]');if(addBtn) addBtn.addEventListener('click',()=>addMultiCityRow(host));host.querySelectorAll('.icon-remove').forEach(btn=>btn.addEventListener('click',()=>btn.closest('.multi-row')?.remove()));});}
function buildRequestURL(form){const host=form.closest('[data-trip-switcher]')||form;const type=host.dataset.tripType||'roundtrip';const qs=new URLSearchParams();qs.set('tripType',type);qs.set('origin',form.querySelector('[name="origin"]')?.value||'');qs.set('destination',form.querySelector('[name="destination"]')?.value||'');qs.set('departDate',form.querySelector('[name="departDate"]')?.value||'');qs.set('returnDate',form.querySelector('[name="returnDate"]')?.value||'');qs.set('cabin',form.querySelector('[name="cabin"]')?.value||'');if(type==='multicity'){const legs=[...host.querySelectorAll('.multi-row')].map(row=>{const inputs=row.querySelectorAll('input');return{origin:inputs[0].value.trim(),destination:inputs[1].value.trim(),departDate:inputs[2].value.trim()};}).filter(r=>r.origin||r.destination||r.departDate);qs.set('multi',JSON.stringify(legs));}return'request.html?'+qs.toString();}
function bindSearchForms(){document.querySelectorAll('[data-flight-search]').forEach(form=>form.addEventListener('submit',e=>{e.preventDefault();window.location.href=buildRequestURL(form);}));}
function fillRequestForm(){const params=new URLSearchParams(window.location.search);const setIf=(name,val)=>{const el=document.querySelector(`[name="${name}"]`);if(el&&val)el.value=val;};['tripType','origin','destination','departDate','returnDate','cabin'].forEach(k=>setIf(k,params.get(k)));const req=document.getElementById('requestTripSwitcher');const multi=params.get('multi');if(req&&params.get('tripType'))setTripType(params.get('tripType'),req);if(multi&&req){try{const legs=JSON.parse(multi);const wrap=req.querySelector('.multi-city-rows');if(wrap){wrap.innerHTML='';legs.forEach(leg=>addMultiCityRow(req,leg));}const summary=document.getElementById('multiCitySummary');if(summary)summary.value=legs.map((r,i)=>`Leg ${i+1}: ${r.origin} → ${r.destination} | ${r.departDate}`).join('\n');}catch(err){}}const key=normalizePlace(params.get('destination'));const box=document.getElementById('destinationInfoBox');if(box&&destinationInfo[key]){box.innerHTML=`<h3>${destinationInfo[key].title}</h3><p>${destinationInfo[key].text}</p>`;}}
function bindSiteSearch(){document.querySelectorAll('[data-site-search]').forEach(form=>form.addEventListener('submit',e=>{e.preventDefault();const input=form.querySelector('input');if(!input||!input.value.trim())return;window.location.href='search.html?q='+encodeURIComponent(input.value.trim());}));}
function renderSearchResults(){const box=document.getElementById('siteSearchResults');if(!box)return;const q=(new URLSearchParams(window.location.search).get('q')||'').trim().toLowerCase();if(!q){box.innerHTML='<p>Search destinations, airports, routes, cabins, lounges, and airline pages.</p>';return;}const tokens=q.split(/\s+/).filter(Boolean);const hits=siteSearchIndex.map(item=>{const hay=[item.title,item.text,...(item.keywords||[])].join(' ').toLowerCase();let score=0;tokens.forEach(t=>{if(hay.includes(t)) score+=1; if((item.title||'').toLowerCase().includes(t)) score+=2;});return {...item,score};}).filter(x=>x.score>0).sort((a,b)=>b.score-a.score).slice(0,24);if(!hits.length){box.innerHTML='<p>No exact page matched that search yet. Try a city, airport code, airline, cabin, lounge, or route.</p>';return;}box.innerHTML='<div class="gallery-grid">'+hits.map(item=>`<a class="gallery-card" href="${item.url}"><div class="copy"><h3>${item.title}</h3><p>${item.text||'Open the page.'}</p></div></a>`).join('')+'</div>';}
function initFlightTracker(){const form=document.getElementById('flightTrackerForm');const out=document.getElementById('flightTrackerOutput');if(!form||!out)return;form.addEventListener('submit',async e=>{e.preventDefault();const code=document.getElementById('flightNumber').value.trim().toUpperCase();if(!code){out.innerHTML='<p>Please enter a flight number.</p>';return;}const data=flightSample[code];if(!data){out.innerHTML='<p>No live result was returned and that flight is not in the current quick-result set yet. Try EK202, BA117, or SQ317.</p>';return;}out.innerHTML=`<table class="compare-table"><tr><th>Flight</th><td>${code}</td></tr><tr><th>Status</th><td>${data.status}</td></tr><tr><th>Departure</th><td>${data.departure}</td></tr><tr><th>Arrival</th><td>${data.arrival}</td></tr><tr><th>Aircraft</th><td>${data.aircraft}</td></tr><tr><th>Airline</th><td>${data.airline}</td></tr><tr><th>Route note</th><td>${data.note}</td></tr></table>`;});}
function initAirlineComparison(){const form=document.getElementById('airlineCompareForm');const out=document.getElementById('airlineCompareOutput');if(!form||!out)return;form.addEventListener('submit',e=>{e.preventDefault();const a=document.getElementById('airlineA').value;const b=document.getElementById('airlineB').value;const cabin=document.getElementById('airlineCabin').value;out.innerHTML=`<table class="compare-table"><tr><th>Cabin</th><th>${a}</th><th>${b}</th></tr><tr><th>Positioning</th><td>${airlineData[a].strength}</td><td>${airlineData[b].strength}</td></tr><tr><th>Best use</th><td>${a} is worth considering when the route and airport flow fit your itinerary.</td><td>${b} is worth considering when the route and airport flow fit your itinerary.</td></tr><tr><th>What to judge</th><td>${cabin} should be judged by privacy, sleep quality, airport fit, and total journey feel.</td><td>${cabin} should be judged by privacy, sleep quality, airport fit, and total journey feel.</td></tr></table>`;});}
function initCabinComparison(){const out=document.getElementById('cabinCompareOutput');const pair=document.getElementById('cabinPair');const btn=document.getElementById('cabinCompareBtn');if(!out||!pair||!btn)return;const data={'business-vs-first':[['Price','Business class is premium and often more attainable.','First class is usually much more expensive and more exclusive.'],['Seat and privacy','Often lie-flat with strong comfort.','Usually offers more personal space and stronger privacy.'],['Dining','Can be excellent on top airlines.','Usually more personalized and more service-intensive.']], 'business-vs-premium':[['Sleep','Business class is built around rest with stronger sleep support.','Premium economy offers more room than economy but not true business-class sleep.'],['Airport','Business usually includes stronger priority handling and lounge access.','Premium economy usually offers fewer ground benefits.']], 'first-vs-premium':[['Experience','Top-end commercial aviation.','Upgraded economy-style comfort.'],['Privacy','Far more space and individual service.','More shared cabin environment.']]};btn.addEventListener('click',()=>{const rows=data[pair.value]||[];out.innerHTML='<table class="compare-table"><tr><th>Topic</th><th>Left cabin</th><th>Right cabin</th></tr>'+rows.map(r=>`<tr><th>${r[0]}</th><td>${r[1]}</td><td>${r[2]}</td></tr>`).join('')+'</table>';});}
function initPriceEstimator(){const form=document.getElementById('priceEstimatorForm');const out=document.getElementById('priceEstimatorOutput');if(!form||!out)return;form.addEventListener('submit',e=>{e.preventDefault();const origin=document.getElementById('priceOrigin').value.trim()||'Origin';const destination=document.getElementById('priceDestination').value.trim()||'Destination';const cabin=document.getElementById('priceCabin').value;const base=cabin==='First Class'?4200:cabin==='Business Class'?2400:1100;out.innerHTML=`<table class="compare-table"><tr><th>Route</th><td>${origin} → ${destination}</td></tr><tr><th>Cabin</th><td>${cabin}</td></tr><tr><th>Estimated range</th><td>$${base.toLocaleString()} – $${Math.round(base*1.7).toLocaleString()}</td></tr></table>`;});}
function initRouteExplorer(){const form=document.getElementById('routeExplorerForm');const out=document.getElementById('routeExplorerOutput');if(!form||!out)return;const routeData={london:['Dubai','Tokyo','Singapore','Rome','New York'],'new york':['London','Dubai','Paris','Rome','Tokyo'],dubai:['London','Paris','New York','Tokyo','Singapore'],paris:['Dubai','New York','London','Tokyo','Singapore']};form.addEventListener('submit',e=>{e.preventDefault();const origin=document.getElementById('routeOrigin').value.trim().toLowerCase();const cabin=document.getElementById('routeCabin').value;const list=routeData[origin];if(!list){out.innerHTML='<p>Try London, New York, Dubai, or Paris.</p>';return;}out.innerHTML='<div class="card-grid">'+list.map(dest=>`<div class="card"><h3>${origin.replace(/(^|\\s)\\S/g,s=>s.toUpperCase())} → ${dest}</h3><p>${cabin} route idea with a direct path into the request form.</p><p><a class="btn btn-secondary" href="../request.html?origin=${encodeURIComponent(origin)}&destination=${encodeURIComponent(dest)}&cabin=${encodeURIComponent(cabin)}">Open Request</a></p></div>`).join('')+'</div>';});}
function initLoungeFinder(){const form=document.getElementById('loungeFinderForm');const out=document.getElementById('loungeFinderOutput');if(!form||!out)return;form.addEventListener('submit',e=>{e.preventDefault();const code=document.getElementById('loungeAirport').value.trim().toUpperCase();const lounges=airportLounges[code];if(!lounges){out.innerHTML='<p>Try JFK, LHR, DXB, SIN, HND, FCO, CDG, or LAX.</p>';return;}out.innerHTML='<div class="result-stack">'+lounges.map(l=>`<div class="result-card"><h3>${l.name}</h3><p><strong>Terminal:</strong> ${l.terminal}</p><p><strong>Access:</strong> ${l.access}</p><p>${l.note}</p></div>`).join('')+'</div>';});}
function initSeatGuide(){const form=document.getElementById('seatGuideForm');const out=document.getElementById('seatGuideOutput');if(!form||!out)return;form.addEventListener('submit',e=>{e.preventDefault();const seat=document.getElementById('seatProduct').value;const bullets=seatProducts[seat];out.innerHTML='<div class="card-grid">'+bullets.map(txt=>`<div class="card"><h3>${seat}</h3><p>${txt}</p></div>`).join('')+'</div>';});}
function initCookieBanner(){const banner=document.getElementById('cookieBanner');if(!banner)return;const key='luxaeris_cookie_choice';if(localStorage.getItem(key))return;banner.style.display='block';['cookieAccept','cookieReject'].forEach(id=>{const btn=document.getElementById(id);if(btn)btn.addEventListener('click',()=>{localStorage.setItem(key,id==='cookieAccept'?'accepted':'rejected');banner.style.display='none';});});}

function isValidAirportSelection(value){
  return !!airportLookup[(value||'').trim()];
}
function markAirportFieldValidity(input){
  if(!input) return true;
  const value=(input.value||'').trim();
  if(!value){
    input.setCustomValidity('Please choose an airport from the list.');
    return false;
  }
  if(!isValidAirportSelection(value)){
    input.setCustomValidity('Please select a valid airport from the dropdown list.');
    return false;
  }
  input.setCustomValidity('');
  return true;
}
function attachAirportValidation(){
  document.querySelectorAll('[data-location-input]').forEach(input=>{
    input.addEventListener('change',()=>markAirportFieldValidity(input));
    input.addEventListener('blur',()=>markAirportFieldValidity(input));
    input.addEventListener('input',()=>{
      if((input.value||'').trim().length < 2){
        input.setCustomValidity('Please type at least 2 characters and choose an airport from the list.');
      }else{
        input.setCustomValidity('');
      }
    });
  });

  document.querySelectorAll('[data-flight-search], form[action*="formspree.io"]').forEach(form=>{
    form.addEventListener('submit',e=>{
      let ok = true;
      form.querySelectorAll('[data-location-input]').forEach(input=>{
        if(input.offsetParent !== null){
          ok = markAirportFieldValidity(input) && ok;
        }
      });

      const host = form.closest('[data-trip-switcher]') || form;
      const multiShell = host.querySelector('.multi-city-shell');
      if(multiShell && multiShell.style.display !== 'none'){
        host.querySelectorAll('.multi-row [data-location-input]').forEach(input=>{
          if(input.offsetParent !== null){
            ok = markAirportFieldValidity(input) && ok;
          }
        });
      }

      if(!ok){
        e.preventDefault();
        const firstInvalid = form.querySelector(':invalid');
        if(firstInvalid) firstInvalid.reportValidity();
      }
    });
  });
}



async function initRouteEstimateTool(){
  const form = document.getElementById('routeEstimateForm');
  const out = document.getElementById('routeEstimateOutput');
  if(!form || !out) return;

  form.querySelectorAll('[data-location-input]').forEach(el=>{
    if((el.value||'').trim().length>=2) el.setAttribute('list','location-options');
  });

  form.addEventListener('submit', async (e)=>{
    e.preventDefault();
    const origin = document.getElementById('estimateOrigin')?.value || '';
    const destination = document.getElementById('estimateDestination')?.value || '';
    const cabin = document.getElementById('estimateCabin')?.value || 'Business Class';
    const departDate = document.getElementById('estimateDepartDate')?.value || '';
    const returnDate = document.getElementById('estimateReturnDate')?.value || '';

    if(!airportLookup[origin] || !airportLookup[destination]){
      out.innerHTML = '<p>Please select valid airports from the dropdown list.</p>';
      return;
    }

    out.innerHTML = '<p>Checking route guidance...</p>';
    try{
      const qs = new URLSearchParams({origin,destination,cabin,departDate,returnDate});
      const res = await fetch('/.netlify/functions/route-estimate?' + qs.toString());
      const data = await res.json();
      if(res.ok && data.route_type){
        out.innerHTML = `
          <table class="compare-table">
            <tr><th>Origin</th><td>${data.origin}</td></tr>
            <tr><th>Destination</th><td>${data.destination}</td></tr>
            <tr><th>Cabin</th><td>${data.cabin}</td></tr>
            <tr><th>Route profile</th><td>${data.route_type}</td></tr>
            <tr><th>Demand profile</th><td>${data.demand_profile}</td></tr>
            <tr><th>Best use</th><td>${data.best_use}</td></tr>
            <tr><th>Recommended next step</th><td>${data.next_step}</td></tr>
            <tr><th>Note</th><td>${data.note}</td></tr>
          </table>`;
        return;
      }
    }catch(err){}
    out.innerHTML = '<p>Route guidance is temporarily unavailable.</p>';
  });
}


document.addEventListener('DOMContentLoaded',()=>{attachDatalists();setDateBounds();bindTripTypeControls();bindSearchForms();fillRequestForm();bindSiteSearch();renderSearchResults();initFlightTracker();initAirlineComparison();initCabinComparison();initPriceEstimator();initRouteExplorer();initLoungeFinder();initSeatGuide();initCookieBanner();initHeroVideo();validateQuoteForm();attachAirportValidation();initRouteEstimateTool();});
